import { join } from 'node:path';
import { bufferWrite } from '../../lib/analytics-buffer.js';
import { safeProjectDir } from '../../lib/paths.js';

export type Mode = 'OFF' | 'AUDIT' | 'REDACT';

export interface AuditEntry {
  readonly timestamp: string;
  readonly tool: string;
  readonly session_id: string;
  readonly mode: Mode;
  readonly action: 'audit' | 'redact' | 'gate';
  readonly pattern_name: string;
  readonly match_count: number;
  /** SHA-256 prefix of matched spans — dedup without storing the secret */
  readonly span_hash: string;
  readonly span_length: number;
}

export function getMode(): Mode {
  const raw = (process.env.ORK_SECRET_HOOK || 'OFF').toUpperCase();
  if (raw === 'AUDIT' || raw === 'REDACT') return raw;
  return 'OFF';
}

/**
 * Append an audit entry to .claude/state/secret-audit.jsonl. Repo-local so
 * .gitignore catches it and audits don't leak across projects. Falls back
 * to ~/.claude/analytics/ if repo-local write fails. Logging is best-effort —
 * never blocks the hook.
 */
export function logAudit(entry: AuditEntry): void {
  const home = process.env.HOME || process.env.USERPROFILE || '';
  const cwd = safeProjectDir();
  const repoLocal = join(cwd, '.claude', 'state', 'secret-audit.jsonl');
  try {
    bufferWrite(repoLocal, `${JSON.stringify(entry)}\n`);
  } catch {
    try {
      bufferWrite(
        join(home, '.claude', 'analytics', 'secret-audit.jsonl'),
        `${JSON.stringify(entry)}\n`,
      );
    } catch {
      /* logging is best-effort */
    }
  }
}

/**
 * Replacement message when a critical pattern fires. Tells the operator
 * exactly how to inspect or disable.
 */
export function gateMessage(criticalName: string): string {
  return (
    `[BLOCKED by ork:secret-handler — output contained ${criticalName}; ` +
    'read the source file directly with care. ' +
    'Set ORK_SECRET_HOOK=AUDIT to inspect what triggered this. ' +
    'Set ORK_SECRET_HOOK=OFF to disable entirely.]'
  );
}
